Widget build(BuildContext context) {
  final styles = _RecordingCoachMarkStyles.of(context);

  return LayoutBuilder(
    builder: (context, constraints) {
      // カードの推定高さを計算
      final estimatedCardHeight = _estimateCardHeight(step);
      // 上部と下部のマージンを考慮
      const totalMargin = 40.0 + 80.0; // 下部40 + 上部バッファ80
      final availableHeight = constraints.maxHeight;

      // センター表示が可能か判定
      final shouldCenter = estimatedCardHeight + totalMargin < availableHeight;

      return Stack(
        alignment: shouldCenter ? Alignment.center : Alignment.bottomCenter,
        children: [
          Container(
            constraints: const BoxConstraints(maxWidth: 390),
            margin: EdgeInsets.only(
              bottom: shouldCenter ? 0 : 40,
            ),
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: _RecordingCoachMarkStyles.cardBorderRadius,
              boxShadow: styles.cardShadows,
            ),
