/// カードの推定高さを計算
double _estimateCardHeight(CoachMarkStep step) {
  // ヘッダー: 56px (padding 12*2 + icon 32)
  double height = 56.0;

  // コンテンツパディング: 12 + 20
  height += 32.0;

  // メディアコンテンツがある場合
  if (step.hasImage) {
    // 画像の推定高さ（幅390の画像を想定）
    height += 200.0; // 平均的な画像高さ
  }
  if (step.hasDescription) {
    // 説明文の推定高さ（2-3行を想定）
    height += 60.0;
  }
  if (step.hasMediaContent) {
    // メディアとチェックリストの間のギャップ
    height += 16.0;
  }

  // チェックリストの高さ
  // 各アイテム: アイコン16 + テキスト高さ24 + 上下パディング
  final itemCount = step.checklistItems.length;
  height += (itemCount * 40.0) + 16.0; // パディング8*2

  // アイテム間のギャップ
  if (itemCount > 1) {
    height += (itemCount - 1) * 12.0;
  }

  return height;
}

